function LCityPeopleMgr:Dispose()
    if (self._isDisposed) then
        return ;
    end
    for i, v in pairs(self._cityPeoples) do
        v:Dispose();
    end
    table.dispose(self._cityPeoples);
    for i, v in pairs(self._peopleHUDs) do
        v:Dispose()
    end
    table.dispose(self._peopleHUDs)
    self._npcTrans = nil;
    self._pathTrans = nil;
    table.dispose(self.birthPoint);
    self.birthPoint = nil;
    table.dispose(self.mainPoint);
    self.mainPoint = nil;
    table.dispose(self.allPathPoint);
    self.allPathPoint = nil;
    if(self.findPathMgr)then
        self.findPathMgr:Dispose()
    end
    self.findPathMgr = nil;
    self.beginTick = false
    self._peopleTick = 0
    self._residentTick = 0;
    self._peopleInitCount = 0;
    self.residentInitCount = 0;
    LCityBase.Dispose(self);
end

