function LCityPeopleMgr:InitTrans(mapTrans)
    if(self._inited)then
        return
    end
    local birthTrans = mapTrans:Find("ShakeRoot/BirthRoot");
    self._npcTrans = mapTrans:Find("ShakeRoot/NpcRoot");
    self._pathTrans = mapTrans:Find("ShakeRoot/PathRoot");
    self._hudCanvasRoot = mapTrans:Find("HUDRoot")
    self._hudCanvas = mapTrans:Find("HUDRoot/HUDCanvas"):GetComponent(typeOfCanvas)
    self._hudCanvas.worldCamera = LxUiHelper.GetSceneCamera()
    local birthCount = birthTrans.childCount;
    for i = 1, birthCount do
        local child = birthTrans:GetChild(i - 1)
        --self.birthPoint[child.position] = false;
        table.insert(self.birthPoint,child.position)
    end

    local mainPointTrans = FindChild(self._pathTrans, "MainPoint");
    local mainPointCount = mainPointTrans.childCount;
    for i = 1, mainPointCount do
        local mainLine = {};
        local mainTrans = mainPointTrans:GetChild(i - 1);
        local mainTransCount = mainTrans.childCount;
        for j = 1, mainTransCount do
            local point = mainTrans:GetChild(j - 1);
            table.insert(mainLine, point.position);
            --self.allPathPoint[point.position] = tonumber(mainTrans.name);
            --table.insert(self.allPathPoint,point.position);
        end
        self.mainPoint[tonumber(mainTrans.name)] = mainLine;
    end
    local allPointTrans = FindChild(self._pathTrans,"PathPoint")
    local pointChildCount = allPointTrans.childCount
    for i = 1, pointChildCount do
        local point = allPointTrans:GetChild(i - 1)
        self.allPathPoint[tonumber(point.name)] = point.position
        --self.allPathPoint[point.position] = tonumber(point.name)
    end
    self:GetTalkCDConfig(true)
    self:GetTalkCDConfig(false)
    self._peopleTick = 0
    self._residentTick = 0;
    self.beginTick = true
    self._inited = true
end
---增加一个人物单元
function LCityPeopleMgr:AddOnePeople(refId,isPeople)

    if(isPeople)then
        if(self._peopleInitCount >= self._initMaxCount)then
            return nil
        end
    else
        if(self._residentInitCount >= self._initMaxCount)then
            return nil
        end
    end

    local people = self:GetPeopleUnit(refId)
    if(people == nil)then
        if(isPeople)then
            local buildId = ModuleCenter.People:GetPeopleObj(refId).building
            if(buildId <= 0)then
                self._peopleInitCount = self._peopleInitCount + 1
            end
        else
            self._residentInitCount = self._residentInitCount + 1
        end

        people = require("LApp.gameplay.city.view.LCityPeopleUnit"):new();
        self._cityPeoples[refId] = people
        people:InitPeople(refId, self,self.LoadPeopleCallBack,self);
    end
    return people
end
function LCityPeopleMgr:LoadPeopleCallBack(refId)

    self:AddPeopleHUD(refId,self._cityPeoples[refId]._peopleObj,self._hudObj)
end
function LCityPeopleMgr:SetPeopleInStory(refId,inStory)
    local people = self:GetPeopleUnit(refId)
    if(people)then
        people:SetInStory(inStory)
    end
end
function LCityPeopleMgr:GetPeopleHUD(refId)
    local hud = self._peopleHUDs[refId]
    return hud;
end
function LCityPeopleMgr:GetPeopleUnit(refId)
    local people = self._cityPeoples[refId]
    return people

end
function LCityPeopleMgr:AddPeopleHUD(refId,peopleTrans,hud)
    local peopleHud = self:GetPeopleHUD(refId)
    if(peopleHud == nil)then
        peopleHud = require("LApp.gameplay.city.view.LCityPeopleHud"):new()
        if(hud == nil)then
            return
        end
        local hudObj = InstantObject(hud)
        hudObj.transform:SetParent(MgrCenter.UIMgr._hudCanvasTrans)
        PJXUtil.SetLayerMask(hudObj.transform,"UI")
        hudObj.transform.localScale = Vector3.one
        peopleHud:SetPeople(refId,peopleTrans,hudObj,self)
        self._peopleHUDs[refId] = peopleHud
        ShowObject(hudObj.gameObject,true)
    end
end

