---获取目标点最近的路径名字
function LCityPeopleMgr:GetPointNearestLine(point)
    local tempDistance = math.maxinteger or (2 ^ 53 - 1)
    local tempLine = 0;
    for i, v in pairs(self.allPathPoint) do
        local distance = Vector3.Distance(point, v);
        if (distance < tempDistance) then
            tempDistance = distance;
            tempLine = i;
        end
    end
    return tempLine;
end
---(废弃)通过建筑ID获取在地图中的位置
---获取建筑中工位的位置
function LCityPeopleMgr:GetBuildPointById(buildRefId,peopleId)
    local buildObj = ModuleCenter.Building:GetBuildingInfo(buildRefId)
    if(buildObj == nil)then
      return  Vector3.zero
    end
    local workIndex = 0;
    for i, v in pairs(buildObj.workers) do
        if(v == peopleId)then
            workIndex = i;
            break
        end
    end
    local transList = CtrlCenter.City:GetCityView()._buildingMgr:GetBuilding(buildRefId)._peopleNodeList
    local trans = nil
    local buildTrans = CtrlCenter.City:GetBuilding(buildRefId)
    if(transList == nil)then
        return buildTrans:GetPosition()
    end
    for i, v in pairs(transList) do
        if(workIndex == i)then
            trans = v;
            break
        end
    end
    if(trans)then
        return trans.position
    end

    return buildTrans:GetPosition()


end

function LCityPeopleMgr:GetBuildPositionById(refId)
    local buildParentTrans = FindChild(self._pathTrans, "Building");
    local buildConfig = GameTable.BuildingRef[refId];
    if(buildConfig == nil)then
        return Vector3.zero
    else
        local buildTrans = FindChild(buildParentTrans, buildConfig.nodeName);
        return buildTrans.position;
    end
end
--获取在寻路路径最后一条路线上距离结束点最近的点
function LCityPeopleMgr:GetEndPointNearestPoint(line,endPoint)
    if(self.mainPoint[line])then
        local linePoints = self.mainPoint[line];
        local tempDistance = math.maxinteger or (2 ^ 53 - 1)
        local tempPoint = nil;
        for i, v in pairs(linePoints) do
            local distance = Vector3.Distance(endPoint,v);
            if(distance < tempDistance)then
                tempDistance = distance;
                tempPoint = v;
            end
        end
        return tempPoint;
    end
    return nil;
end
function LCityPeopleMgr:GetPointById(id)
    return self.allPathPoint[id]
end
---获取路上距离这个点和目标点最近的点
function LCityPeopleMgr:GetNearestPoint(lineList, curPoint, passList,endPoint)
    local tempDistance = math.maxinteger or (2 ^ 53 - 1)
    local tempPoint = nil;
    local tempEndDistance = Vector3.Distance(curPoint,endPoint)
    for i, line in pairs(lineList) do
        if(self.mainPoint[line])then
            local linePoint = self.mainPoint[line];
            for j, point in pairs(linePoint) do
                if(table.keyof(passList,point) == nil)then
                    local nextDistance = Vector3.Distance(curPoint,point)
                    local endDistance = Vector3.Distance(endPoint,point)
                    if(nextDistance < tempDistance and endDistance < tempEndDistance)then
                        tempDistance = nextDistance;
                        tempEndDistance = endDistance;
                        tempPoint = point;
                    end
                end
            end
        end
    end
    return tempPoint;
end
---@param people true:居民  false:流民
function LCityPeopleMgr:GetTalkCDConfig(people)
    local config = nil
    if(people)then
        config = GameTable.PeopleConfigRef.peopleTalk2CD
    else
        config = GameTable.PeopleConfigRef.peopleTalk1CD
    end
    local info = string.split(config,"=")
    local nums = checknumber(info[1])
    local radio = checknumber(info[2])
    local cd = checknumber(info[3])
    if(people)then
        table.insert(self._peopleCdInfos,nums)
        table.insert(self._peopleCdInfos,radio)
        table.insert(self._peopleCdInfos,cd)
    else
        table.insert(self._residentCdInfos,nums)
        table.insert(self._residentCdInfos,radio)
        table.insert(self._residentCdInfos,cd)
    end
    return nums,radio,cd
end
function LCityPeopleMgr:OnUpdate(deltaTime)
    for i, v in pairs(self._cityPeoples) do
        v:OnUpdate(deltaTime)
    end
    for i, v in pairs(self._peopleHUDs) do
        v:OnUpdate(deltaTime)
    end
    if(self.beginTick)then
        self._peopleTick = self._peopleTick + deltaTime
        self._residentTick = self._residentTick + deltaTime
        if(self._peopleTick >= self._peopleCdInfos[3])then
            --开始随机要说话的居民
            local refId = self:RandomTalkpeople(self._peopleCdInfos,ModuleCenter.People._peoples)
            if(refId ~= nil and self:CheckPeopleState(refId))then
                local hud = self._peopleHUDs[refId]
                if hud then
                    hud:ShowChatText()
                end
            end
            self._peopleTick = 0;
        end
        if(self._residentTick >= self._residentCdInfos[3])then
            --随机要说话的流民
            local refId = self:RandomTalkpeople(self._residentCdInfos,ModuleCenter.People._homeless)
            if(refId ~= nil and self:CheckPeopleState(refId))then
                if(self._peopleHUDs[refId])then
                    self._peopleHUDs[refId]:ShowChatText()
                end

            end
            self._residentTick = 0
        end
    end
end
---居民闲聊只出现在未招纳，闲置，寻路时，判断是否满足条件
function LCityPeopleMgr:CheckPeopleState(refId)
    local unit = self._cityPeoples[refId]
    if(unit == nil or unit._peopleFsm == nil)then
        return false
    end
    local curState = unit._peopleFsm:GetCurState()._stateType
    if(curState == CityPeopleFsmState.Idle or curState == CityPeopleFsmState.FindPath or curState == CityPeopleFsmState.Birth)then
        return true
    end
    return false
end
function LCityPeopleMgr:RandomTalkpeople(peopleCdInfo,peopleList)
    local r = math.random(1,100)
    if(r > peopleCdInfo[2])then
        --可以说话
        return self:GetTalkPeopleRefId(peopleList)
    end
    return nil
end
function LCityPeopleMgr:GetTalkPeopleRefId(list)
    local length = table.nums(list)
    local index = math.random(1,length)
    local refId = self:GetPeopleDataByIndex(list,index)
    return refId
end
function LCityPeopleMgr:GetPeopleDataByIndex(list,index)
    local cur = 0;
    for i, v in pairs(list) do
        cur = cur+1
        if(cur == index)then
            return v.refId;
        end
    end
    return nil
end
