function LCityPeopleMgr:NewPeoples(data)
    local num = data.num
    self._residentInitCount = self._residentInitCount - num

    self:AddPeoples()
end
function LCityPeopleMgr:GetPoeplePosConfig(refId)
    local dataList = ModuleCenter.People:GetHasPeopleList()
    local temp = {}
    for i, v in pairs(dataList) do
        if(v.building <= 0)then
            table.insert(temp,v)
        end
    end
    for i, v in pairs(temp) do
        if(v.refId == refId)then
            return GameTable.PeopleSiteRef[i]
        end
    end
    return nil
end
function LCityPeopleMgr:GetResidentPosConfig(refId)
    local dataList = ModuleCenter.People:GetRecruitList()

    local index = 0;
    for i, v in pairs(dataList) do
        index = index + 1
        if(v.refId == refId)then
            return GameTable.PeopleSiteRef[index]
        end
    end
    return nil
end
function LCityPeopleMgr:DeletePeople(data)
    local refId = data.refId
    local peopleObj = ModuleCenter.People:GetPeopleObj(refId)
    if(peopleObj ~= nil)then
        if(peopleObj.building <= 0)then
            self._peopleInitCount = self._peopleInitCount - 1
        end
    end

    local people = self._cityPeoples[refId]
    if(people)then
        people:Dispose();
        self._cityPeoples[refId] = nil
    end
    local peopleHud = self._peopleHUDs[refId]
    if(peopleHud)then
        peopleHud:Dispose()
        self._peopleHUDs[refId] = nil
    end
end
---获取居民
function LCityPeopleMgr:GetPeoples()
    local res = {}
    for i, v in pairs(self._cityPeoples) do
        if(ModuleCenter.People:CheckIsResident(i))then
            table.insert(res,v);
        end
    end
    return res;
end
--生病，去住院
function LCityPeopleMgr:GotoHospital()
    local list = self:GetPeoples()
    for i, v in pairs(list) do
        v:GotoHospital();
    end
end
--从医院出来
function LCityPeopleMgr:OutHospital(data)
    local refId = data.refId
    local list = self:GetPeoples()
    for i, v in pairs(list) do
        v:OutHospital(refId);
    end
end
--工作
function LCityPeopleMgr:GotoWork()
    local list = self:GetPeoples()
    for i, v in pairs(list) do
        v:GotoWork();
        v:SetEatNode(nil)
        v:SetEatEnd(false)
    end
end
--睡觉
function LCityPeopleMgr:GotoSleep()
    local list = self:GetPeoples()
    for i, v in pairs(list) do
        v:GotoSleep()
        v:SetEatNode(nil)
        v:SetEatEnd(false)
    end
end
--吃饭
function LCityPeopleMgr:GotoEat()
    local list = self:GetPeoples()
    for i, v in pairs(list) do
        v:GotoEat()
    end
end


--使用民心技能
function LCityPeopleMgr:UsePeopleSkill(data)
    local skillId = data.skillId
    if(skillId == 1002)then
        --半夜鸡叫，只能在睡觉的时候使用，使用之后把居民从床上叫起来去工作
        self:GotoWork()
    end
    if(skillId == 1007)then
        --寻医问药，使用后所有生病居民痊愈，从医院跑到出生点
        --这个技能的表现由居民通知控制
    end
    for i, v in pairs(self._peopleHUDs) do
        v:ShowSkillText(skillId);
    end
end

function LCityPeopleMgr:ContinueEat()
    for i, v in pairs(self._cityPeoples) do
        if(ModuleCenter.People:CheckIsResident(v._peopleRefId))then
            v:GotoEat()
        end
    end
end
return LCityPeopleMgr






